const i=performance,u=9,f=6,a=Math.pow(10,f),e=Math.pow(10,u);function s(n){const o=n/1e3,r=Math.trunc(o),t=Math.round(n%1e3*a);return[r,t]}function T(n){const o=s(i.timeOrigin),r=s(typeof n=="number"?n:i.now());return p(o,r)}function N(n){if(c(n))return n;if(typeof n=="number")return n<i.timeOrigin?T(n):s(n);if(n instanceof Date)return s(n.getTime());throw TypeError("Invalid input type")}function O(n,o){let r=o[0]-n[0],t=o[1]-n[1];return t<0&&(r-=1,t+=e),[r,t]}function I(n){return n[0]*e+n[1]}function S(n){return n[0]*1e6+n[1]/1e3}function c(n){return Array.isArray(n)&&n.length===2&&typeof n[0]=="number"&&typeof n[1]=="number"}function h(n){return c(n)||typeof n=="number"||n instanceof Date}function p(n,o){const r=[n[0]+o[0],n[1]+o[1]];return r[1]>=e&&(r[1]-=e,r[0]+=1),r}export{T as a,O as b,c,p as d,S as e,I as h,h as i,s as m,i as o,N as t};
